105→export default {
106→  async fetch(request: Request, env: Env): Promise<Response> {
107→    try {
108→      const auth = await getAuthenticatedUserOrDev(request, env);
109→      const url = new URL(request.url);
110→      const path = url.pathname;
111→      const method = request.method;
112→
113→      // ── GET /programs/default.json ─────────────────────────────
114→      if (method === "GET" && path === "/programs/default.json") {
115→        return new Response(JSON.stringify(defaultProgramJson, null, 2), {
116→          headers: {
117→            "content-type": "application/json",
118→            "content-disposition": 'attachment; filename="default-program.json"',
119→          },
120→        });
121→      }
122→
123→      // ── GET / ──────────────────────────────────────────────────
124→      if (method === "GET" && path === "/") {
125→        const user = await getUser(env.DB, auth.userId);
126→        if (!user) {
127→          return htmlResponse(
128→            htmlShell({
129→              title: APP_NAME,
130→              subtitle: "Setup",
131→              body: `<div id="content">${setupPage()}</div>`,
132→            })
133→          );
134→        }
135→
136→        if (isSSERequest(request)) {
137→          return await handleTodaySSE(env, auth.userId);
138→        }
139→
140→        const subtitle = await loadSubtitle(env.DB, auth.userId);
141→        return htmlResponse(
142→          htmlShell({
143→            title: APP_NAME,
144→            subtitle,
145→            activeTab: "today",
146→            ssePath: "/",
147→          })
148→        );
149→      }
150→
151→      // ── GET /progress ──────────────────────────────────────────
152→      if (method === "GET" && path === "/progress") {
153→        if (isSSERequest(request)) {
154→          return await handleProgressSSE(env, auth.userId);
155→        }
156→
157→        const subtitle = await loadSubtitle(env.DB, auth.userId);
158→        return htmlResponse(
159→          htmlShell({
160→            title: "Progress",
161→            subtitle,
162→            activeTab: "progress",
163→            ssePath: "/progress",
164→          })
165→        );
166→      }
167→
168→      // ── GET /program ──────────────────────────────────────────
169→      if (method === "GET" && path === "/program") {
170→        if (isSSERequest(request)) {
171→          return await handleProgramSSE(env, auth.userId);
172→        }
173→
174→        const subtitle = await loadSubtitle(env.DB, auth.userId);
175→        return htmlResponse(
176→          htmlShell({
177→            title: "Program",
178→            subtitle,
179→            activeTab: "program",
180→            ssePath: "/program",
181→          })
182→        );
183→      }
184→
185→      // ── GET /routine/:id ──────────────────────────────────────
186→      const routineMatch = path.match(/^\/routine\/([^/]+)$/);
187→      if (method === "GET" && routineMatch) {
188→        const routineId = decodeURIComponent(routineMatch[1]);
189→
190→        if (isSSERequest(request)) {
191→          return await handleRoutineSSE(env, auth.userId, routineId);
192→        }
193→
194→        return htmlResponse(
195→          htmlShell({
196→            title: "Routine",
197→            activeTab: "today",
198→            ssePath: `/routine/${encodeURIComponent(routineId)}`,
199→          })
200→        );
201→      }
202→
203→      // ── POST /api/validate-program ─────────────────────────────
204→      if (method === "POST" && path === "/api/validate-program") {
205→        return await handleValidateProgram(request);
206→      }
207→
208→      // ── POST /api/setup/:templateId ─────────────────────────────
209→      const setupMatch = path.match(/^\/api\/setup\/([^/]+)$/);
210→      if (method === "POST" && (path === "/api/setup" || setupMatch)) {
211→        const urlTemplateId = setupMatch ? decodeURIComponent(setupMatch[1]) : undefined;
212→        return await handleSetup(request, env, auth.userId, urlTemplateId);
213→      }
214→
215→      // ── POST /api/push-hevy/:id ────────────────────────────────
216→      const pushMatch = path.match(/^\/api\/push-hevy\/([^/]+)$/);
217→      if (method === "POST" && pushMatch) {
218→        const routineId = decodeURIComponent(pushMatch[1]);
219→        return await handlePush(env, auth.userId, routineId);
220→      }
221→
222→      // ── POST /api/pull ─────────────────────────────────────────
223→      if (method === "POST" && path === "/api/pull") {
224→        return await handlePull(env, auth.userId);
225→      }
226→
227→      // ── POST /api/cleanup-routines ───────────────────────────────
228→      if (method === "POST" && path === "/api/cleanup-routines") {
229→        return await handleCleanupRoutines(env, auth.userId);
230→      }
231→
232→      // ── POST /api/complete/:id ─────────────────────────────────
233→      const completeMatch = path.match(/^\/api\/complete\/([^/]+)$/);
234→      if (method === "POST" && completeMatch) {
235→        const itemId = parseInt(completeMatch[1], 10);
236→        return await handleManualComplete(env, auth.userId, itemId);
237→      }
238→
239→      // ── 404 ────────────────────────────────────────────────────
240→      return new Response("Not Found", { status: 404 });
241→    } catch (err) {
242→      if (err instanceof Response) return err;
243→      const message = err instanceof Error ? err.message : "Internal Server Error";
244→      const stack = err instanceof Error ? err.stack : "";
245→      console.error("Unhandled error:", message, stack);
246→      return new Response(message, { status: 500 });
247→    }
248→  },
249→};
