255→/** POST /api/validate-program — validate uploaded JSON, return template cards */
256→async function handleValidateProgram(request: Request): Promise<Response> {
257→  const body = (await request.json()) as Record<string, unknown>;
258→  // Fall back to bundled default program if none uploaded
259→  const programJsonStr = (body.programJson as string | undefined) || JSON.stringify(defaultProgramJson);
260→
261→  let parsed: unknown;
262→  try {
263→    parsed = JSON.parse(programJsonStr);
264→  } catch {
265→    return sseResponse(
266→      patchElements(
267→        `<div class="card"><p style="color:var(--orange)">Invalid JSON file.</p></div>`,
268→        { selector: "#validation-result", mode: "inner" }
269→      )
270→    );
271→  }
272→
273→  const result = validateProgram(parsed);
274→  if (!result.valid) {
275→    const errorList = result.errors
276→      .map((e) => `<li>${escapeHtml(e)}</li>`)
277→      .join("");
278→    return sseResponse(
279→      patchElements(
280→        `<div class="card"><p style="color:var(--orange)">Validation errors:</p><ul style="margin:8px 0 0 16px;font-size:13px;color:var(--text-secondary)">${errorList}</ul></div>`,
281→        { selector: "#validation-result", mode: "inner" }
282→      )
283→    );
284→  }
285→
286→  return sseResponse(
287→    patchElements(templateSelectionFragment(result.program.weekTemplates), {
288→      selector: "#validation-result",
289→      mode: "inner",
290→    })
291→  );
292→}
