294→/** SSE: Today page — CARs card, hero session, completed, upcoming */
295→async function handleTodaySSE(env: Env, userId: string): Promise<Response> {
296→  const user = await getUser(env.DB, userId);
297→  if (!user) {
298→    return sseResponse(
299→      patchElements(setupPage(), { selector: "#content", mode: "inner" })
300→    );
301→  }
302→
303→  const program = await loadProgram(env.DB, userId);
304→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
305→  const dailyRoutine = program.routines.find((r) => r.isDaily);
306→
307→  const items = await getQueueItems(env.DB, userId);
308→  const today = todayString();
309→
310→  // Look up routine mappings for deep links
311→  const routineMappings = await getRoutineMappings(env.DB, userId);
312→  const routineToHevyId = new Map(
313→    routineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
314→  );
315→
316→  const fragments: string[] = [];
317→
318→  if (dailyRoutine) {
319→    fragments.push(patchElements(carsCard(dailyRoutine, routineToHevyId.get(dailyRoutine.id)), { selector: "#content", mode: "inner" }));
320→  }
321→
322→  // Hero session card — next pending
323→  const nextItem = getNextRoutine(items);
324→  if (nextItem) {
325→    const routine = routineMap.get(nextItem.routine_id);
326→    if (routine) {
327→      fragments.push(
328→        patchElements(heroRoutineCard(routine, nextItem), { selector: "#content", mode: "append" })
329→      );
330→    }
331→  }
332→
333→  // Completed today
334→  const completed = getCompletedRoutines(items, today);
335→  if (completed.length > 0) {
336→    const completedData = completed.map((item) => ({
337→      title: routineMap.get(item.routine_id)?.title ?? item.routine_id,
338→    }));
339→    fragments.push(
340→      patchElements(completedSection(completedData), { selector: "#content", mode: "append" })
341→    );
342→  }
343→
344→  // Upcoming (next 5 sessions)
345→  const template = program.weekTemplates.find((t) => t.id === user.template_id);
346→  if (template) {
347→    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
348→    // Skip the first pending (already shown as hero) for upcoming
349→    const upcomingPending = pendingItems.slice(1);
350→    const upcoming = computeUpcoming(upcomingPending, template, program.routines, 5);
351→    if (upcoming.length > 0) {
352→      fragments.push(
353→        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
354→      );
355→    }
356→  }
357→
358→  // Sync button at the bottom
359→  fragments.push(
360→    patchElements(syncButton(), { selector: "#content", mode: "append" })
361→  );
362→
363→  return sseResponse(mergeFragments(fragments));
364→}
