464→/** POST /api/setup — store program, sync Hevy, create user, generate queue */
465→async function handleSetup(request: Request, env: Env, userId: string, urlTemplateId?: string): Promise<Response> {
466→  let body: { apiKey?: string; startDate?: string; templateId?: string; programJson?: string } = {};
467→  try {
468→    body = (await request.json()) as typeof body;
469→  } catch {
470→    // Body may be empty — that's OK, template ID comes from URL
471→  }
472→
473→  const templateId = urlTemplateId ?? body.templateId;
474→  const startDate = body.startDate || todayString();
475→  const apiKey = body.apiKey || undefined;
476→  // Fall back to bundled default program if none uploaded
477→  const programJsonStr = body.programJson || JSON.stringify(defaultProgramJson);
478→
479→  if (!templateId) {
480→    return new Response("Template ID is required", { status: 400 });
481→  }
482→
483→  // Parse and validate program
484→  let program: Program;
485→  try {
486→    const parsed = JSON.parse(programJsonStr);
487→    const result = validateProgram(parsed);
488→    if (!result.valid) {
489→      return new Response(`Invalid program: ${result.errors.join(", ")}`, { status: 400 });
490→    }
491→    program = result.program;
492→  } catch {
493→    return new Response("Invalid program JSON", { status: 400 });
494→  }
495→
496→  const template = program.weekTemplates.find((t) => t.id === templateId);
497→  if (!template) {
498→    return new Response("Invalid template ID", { status: 400 });
499→  }
500→
501→  // Validate API key against Hevy before proceeding
502→  if (apiKey) {
503→    try {
504→      const client = new HevyClient(apiKey);
505→      await client.getExerciseTemplates(1, 1);
506→    } catch {
507→      return sseResponse(
508→        patchElements(
509→          `<div class="card"><p style="color:var(--orange)">Invalid Hevy API key. Check your key in Hevy Settings &gt; Developer and try again.</p></div>`,
510→          { selector: "#content", mode: "prepend" }
511→        )
512→      );
513→    }
514→  }
515→
516→  // h. Upsert user (must exist before program insert due to FK constraint)
517→  await upsertUser(env.DB, {
518→    id: userId,
519→    active_program: program.meta.title,
520→    template_id: templateId,
521→    start_date: startDate,
522→    hevy_api_key: apiKey,
523→  });
524→
525→  // a. Store program in D1
526→  await insertProgram(env.DB, userId, programJsonStr);
527→
528→  // b-g. Hevy exercise template & routine creation (only with API key)
529→  const routineIdMap = new Map<string, string>();
530→  if (apiKey) {
531→    const client = new HevyClient(apiKey);
532→
533→    // b. Fetch all Hevy exercise templates
534→    const hevyTemplates = await client.getAllExerciseTemplates();
535→
536→    // c. Auto-match our templates to Hevy's by normalized title
537→    const matched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
538→
539→    // d. Create custom Hevy exercise templates for unmatched
540→    const customCreated = new Set<string>();
541→    for (const et of program.exerciseTemplates) {
542→      if (!matched.has(et.id)) {
543→        const enums = mapToHevyEnums(et);
544→        const created = await client.createExerciseTemplate({
545→          title: et.title,
546→          exercise_type: enums.exerciseType,
547→          equipment_category: enums.equipmentCategory,
548→          muscle_group: enums.primaryMuscleGroup,
549→          other_muscles: enums.secondaryMuscleGroups,
550→        });
551→        matched.set(et.id, created.id);
552→        customCreated.add(et.id);
553→      }
554→    }
555→
556→    // e. Save all exercise template mappings
557→    for (const [programTemplateId, hevyTemplateId] of matched) {
558→      await upsertExerciseTemplateMapping(env.DB, {
559→        user_id: userId,
560→        program_template_id: programTemplateId,
561→        hevy_template_id: hevyTemplateId,
562→        is_custom: customCreated.has(programTemplateId) ? 1 : 0,
563→      });
564→    }
565→
566→    // f. Create or update Hevy routines with folder grouping + dedup
567→    const allMappings = await getExerciseTemplateMappings(env.DB, userId);
568→    const existingRoutineMappings = await getRoutineMappings(env.DB, userId);
569→    const existingMappingsMap = new Map(
570→      existingRoutineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
571→    );
572→
573→    // Compute folder assignments and create/find folders
574→    const folderAssignments = computeFolderAssignments(program.routines, program.meta.title);
575→    const uniqueFolderNames = [...new Set(folderAssignments.map((a) => a.folderName))];
576→    const folderNameToId = new Map<string, number>();
577→    for (const name of uniqueFolderNames) {
578→      const folder = await client.getOrCreateRoutineFolder(name);
579→      folderNameToId.set(name, folder.id);
580→    }
581→
582→    // Fetch existing Hevy routines for dedup by title+folder
583→    const existingHevyRoutines = await client.getAllRoutines();
584→
585→    // Reconcile: decide create vs update for each routine
586→    const reconciliations = reconcileRoutines(
587→      folderAssignments, existingHevyRoutines, folderNameToId, existingMappingsMap
588→    );
589→
590→    for (const recon of reconciliations) {
591→      const routine = program.routines.find((r) => r.id === recon.programRoutineId)!;
592→      const payload = buildRoutinePayload(routine, allMappings);
593→      const folderId = folderNameToId.get(recon.folderName)!;
594→
595→      if (recon.action === "update" && recon.existingHevyRoutineId) {
596→        await client.updateRoutine(recon.existingHevyRoutineId, {
597→          title: payload.title,
598→          exercises: payload.exercises,
599→        });
600→        routineIdMap.set(routine.id, recon.existingHevyRoutineId);
601→      } else {
602→        const created = await client.createRoutine({
603→          title: payload.title,
604→          folder_id: folderId,
605→          exercises: payload.exercises,
606→        });
607→        routineIdMap.set(routine.id, created.id);
608→      }
609→    }
610→
611→    // g. Save all routine mappings
612→    for (const [programRoutineId, hevyRoutineId] of routineIdMap) {
613→      await upsertRoutineMapping(env.DB, {
614→        user_id: userId,
615→        program_routine_id: programRoutineId,
616→        hevy_routine_id: hevyRoutineId,
617→      });
618→    }
619→  }
620→
621→  // i. Generate queue playlist
622→  const weeks = program.meta.durationWeeks || 8;
623→  const playlist = generatePlaylist(template, program.routines, weeks);
624→  if (playlist.length > 0) {
625→    await insertQueueItems(env.DB, userId, playlist);
626→  }
627→
628→  // j. Bulk-set hevy_routine_id on queue items via routine_mappings
629→  if (apiKey) {
630→    await bulkSetQueueItemRoutineIds(env.DB, userId, routineIdMap);
631→  }
632→
633→  // k. Redirect to Today
634→  return sseResponse(executeScript("window.location.href = '/'"));
635→}
