637→/** POST /api/push-hevy/:id — open routine in Hevy (uses existing mapping from setup) */
638→async function handlePush(env: Env, userId: string, routineId: string): Promise<Response> {
639→  const user = await getUser(env.DB, userId);
640→  if (!user || !user.hevy_api_key) {
641→    return sseResponse(
642→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
643→        selector: "#content",
644→        mode: "inner",
645→      })
646→    );
647→  }
648→
649→  // Look up existing routine mapping from setup
650→  const routineMappings = await getRoutineMappings(env.DB, userId);
651→  const mapping = routineMappings.find((m) => m.program_routine_id === routineId);
652→
653→  if (mapping) {
654→    // Routine already exists in Hevy — open it directly
655→    return sseResponse(
656→      executeScript(`window.open('https://hevy.com/routine/${mapping.hevy_routine_id}', '_blank')`)
657→    );
658→  }
659→
660→  // Fallback: no mapping exists (edge case — setup didn't create this routine)
661→  const program = await loadProgram(env.DB, userId);
662→  const routine = program.routines.find((r) => r.id === routineId);
663→  if (!routine) {
664→    return new Response("Routine not found", { status: 404 });
665→  }
666→
667→  const client = new HevyClient(user.hevy_api_key);
668→
669→  // Get or auto-create exercise template mappings
670→  let mappings = await getExerciseTemplateMappings(env.DB, userId);
671→  if (mappings.length === 0) {
672→    try {
673→      const hevyTemplates = await client.getAllExerciseTemplates();
674→      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
675→
676→      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
677→        await upsertExerciseTemplateMapping(env.DB, {
678→          user_id: userId,
679→          program_template_id: programTemplateId,
680→          hevy_template_id: hevyTemplateId,
681→          is_custom: 0,
682→        });
683→      }
684→      mappings = await getExerciseTemplateMappings(env.DB, userId);
685→    } catch {
686→      // If auto-match fails, continue with empty mappings
687→    }
688→  }
689→
690→  const payload = buildRoutinePayload(routine, mappings);
691→
692→  if (payload.exercises.length === 0) {
693→    return sseResponse(
694→      patchElements(
695→        `<div class="card"><p style="color:var(--orange)">Cannot push: no exercises could be mapped to Hevy templates. ${payload.unmapped.length} unmapped exercise(s).</p></div>`,
696→        { selector: "#content", mode: "prepend" }
697→      )
698→    );
699→  }
700→
701→  try {
702→    const folder = await client.getOrCreateRoutineFolder(program.meta.title);
703→    const created = await client.createRoutine({
704→      title: payload.title,
705→      folder_id: folder.id,
706→      exercises: payload.exercises,
707→    });
708→
709→    // Save the mapping so future pushes use the existing routine
710→    await upsertRoutineMapping(env.DB, {
711→      user_id: userId,
712→      program_routine_id: routineId,
713→      hevy_routine_id: created.id,
714→    });
715→
716→    // Also update the queue item if there is one
717→    const items = await getQueueItems(env.DB, userId);
718→    const queueItem = items.find(
719→      (i) => i.routine_id === routineId && i.status === "pending"
720→    );
721→    if (queueItem) {
722→      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, created.id);
723→    }
724→
725→    return sseResponse(
726→      executeScript(`window.open('https://hevy.com/routine/${created.id}', '_blank')`)
727→    );
728→  } catch (err) {
729→    const msg = escapeHtml(err instanceof Error ? err.message : "Push failed");
730→    return sseResponse(
731→      patchElements(
732→        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
733→        { selector: "#content", mode: "prepend" }
734→      )
735→    );
736→  }
737→}
