739→/** POST /api/cleanup-routines — delete duplicate routines from Hevy */
740→async function handleCleanupRoutines(env: Env, userId: string): Promise<Response> {
741→  const user = await getUser(env.DB, userId);
742→  if (!user || !user.hevy_api_key) {
743→    return sseResponse(
744→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
745→        selector: "#content",
746→        mode: "prepend",
747→      })
748→    );
749→  }
750→
751→  const client = new HevyClient(user.hevy_api_key);
752→  const allRoutines = await client.getAllRoutines();
753→
754→  // Group by title+folder, find duplicates
755→  const byKey = new Map<string, typeof allRoutines>();
756→  for (const r of allRoutines) {
757→    const key = `${r.title}::${r.folder_id ?? "none"}`;
758→    const list = byKey.get(key) ?? [];
759→    list.push(r);
760→    byKey.set(key, list);
761→  }
762→
763→  const toDelete: string[] = [];
764→  for (const [, routines] of byKey) {
765→    if (routines.length > 1) {
766→      // Keep the most recently updated, delete the rest
767→      routines.sort((a, b) => (b.updated_at ?? "").localeCompare(a.updated_at ?? ""));
768→      toDelete.push(...routines.slice(1).map((r) => r.id));
769→    }
770→  }
771→
772→  let deleted = 0;
773→  let failed = 0;
774→  for (const id of toDelete) {
775→    try {
776→      await client.deleteRoutine(id);
777→      deleted++;
778→    } catch {
779→      failed++;
780→    }
781→  }
782→
783→  const msg = toDelete.length === 0
784→    ? "No duplicates found."
785→    : `Cleaned up ${deleted} duplicate(s)${failed > 0 ? `, ${failed} failed` : ""}.`;
786→
787→  return sseResponse(
788→    patchElements(
789→      `<div class="card"><p style="color:var(--green)">${escapeHtml(msg)}</p></div>`,
790→      { selector: "#content", mode: "prepend" }
791→    )
792→  );
793→}
