795→/** POST /api/pull — pull completions from Hevy */
796→async function handlePull(env: Env, userId: string): Promise<Response> {
797→  const user = await getUser(env.DB, userId);
798→  if (!user || !user.hevy_api_key) {
799→    return sseResponse(
800→      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
801→        selector: "#content",
802→        mode: "inner",
803→      })
804→    );
805→  }
806→
807→  const program = await loadProgram(env.DB, userId);
808→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
809→  const client = new HevyClient(user.hevy_api_key);
810→
811→  try {
812→    const [workouts, items] = await Promise.all([
813→      client.getRecentWorkouts(),
814→      getQueueItems(env.DB, userId),
815→    ]);
816→    const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);
817→
818→    const nameToRoutineId = new Map<string, string>();
819→    for (const item of pendingItems) {
820→      const routine = routineMap.get(item.routine_id);
821→      if (routine && item.hevy_routine_id) {
822→        nameToRoutineId.set(routine.title, item.hevy_routine_id);
823→      }
824→    }
825→
826→    const matches = matchCompletions(
827→      pendingItems,
828→      workouts,
829→      (w) => nameToRoutineId.get(w.title) ?? null
830→    );
831→
832→    const today = todayString();
833→    for (const match of matches) {
834→      await markQueueItemCompleted(env.DB, match.queueItemId, today, match.workoutId);
835→    }
836→
837→    // Re-render today page
838→    return await handleTodaySSE(env, userId);
839→  } catch (err) {
840→    const msg = escapeHtml(err instanceof Error ? err.message : "Pull failed");
841→    return sseResponse(
842→      patchElements(
843→        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
844→        { selector: "#content", mode: "prepend" }
845→      )
846→    );
847→  }
848→}
