44→export function getCompletedRoutines(items: QueueItemRow[], today: string): QueueItemRow[] {
45→  return items
46→    .filter((item) => item.status === "completed" && item.completed_date === today)
47→    .sort((a, b) => a.position - b.position);
48→}
