 3→
 4→export interface UpcomingItem {
 5→  type: "routine" | "spacer";
 6→  routineId?: string;
 7→  title: string;
 8→  exerciseCount?: number;
 9→  color?: string;
10→}
11→
12→export function computeUpcoming(
13→  pendingItems: QueueItemRow[],
14→  template: WeekTemplate,
15→  routines: Routine[],
16→  maxSessions: number
17→): UpcomingItem[] {
18→  const routineMap = new Map(routines.map((r) => [r.id, r]));
19→
20→  // Build the template rhythm: which day indices are spacers vs routines
21→  const templateRhythm: Array<{ type: "routine" | "spacer"; routineId?: string }> = [];
22→  for (const day of template.days) {
23→    const mainIds = (day.routineIDs ?? []).filter((rid) => {
24→      const r = routineMap.get(rid);
25→      return r && !r.isDaily;
26→    });
27→    if (mainIds.length === 0 && (day.routineIDs ?? []).length > 0) {
28→      templateRhythm.push({ type: "spacer" });
29→    } else if (mainIds.length > 0) {
30→      for (const rid of mainIds) {
31→        templateRhythm.push({ type: "routine", routineId: rid });
32→      }
33→    }
34→  }
35→
36→  const result: UpcomingItem[] = [];
37→  let rhythmIndex = 0;
38→  let sessionCount = 0;
39→
40→  const firstPending = pendingItems[0];
41→  if (firstPending) {
42→    for (let i = 0; i < templateRhythm.length; i++) {
43→      if (templateRhythm[i].routineId === firstPending.routine_id) {
44→        rhythmIndex = i;
45→        break;
46→      }
47→    }
48→  }
49→
50→  let pendingIdx = 0;
51→  while (sessionCount < maxSessions && pendingIdx < pendingItems.length) {
52→    const rhythmSlot = templateRhythm[rhythmIndex % templateRhythm.length];
53→
54→    if (rhythmSlot.type === "spacer") {
55→      result.push({ type: "spacer", title: "CARs only" });
56→    } else {
57→      const item = pendingItems[pendingIdx];
58→      const routine = routineMap.get(item.routine_id);
59→      result.push({
60→        type: "routine",
61→        routineId: item.routine_id,
62→        title: routine?.title ?? item.routine_id,
63→        exerciseCount: routine?.exercises.length,
64→        color: routine?.color,
65→      });
66→      pendingIdx++;
67→      sessionCount++;
68→    }
69→
70→    rhythmIndex++;
71→  }
72→
73→  return result;
74→}
