171→ * Build a Hevy exercise template creation payload from a domain ExerciseTemplate.
172→ * Pure mapping from domain shape (camelCase) to wire shape (snake_case).
173→ */
174→export function buildExerciseTemplatePayload(
175→  template: ExerciseTemplate
176→): ExerciseTemplatePayload {
177→  return {
178→    title: template.title,
